@extends('layouts.app') @section('content') <h2>Shopping Cart</h2> @if($carts->isEmpty()) <p>Your cart is empty.</p> @else <table class="table"> <thead> <tr> <th>Product</th> <th>Price</th> <th>Quantity</th> <th>Total</th> <th>Actions</th> </tr> </thead> <tbody> @php $total = 0; @endphp @foreach($carts as $c) @php $total += $c->product->price * $c->quantity; @endphp <tr> <td>{{ $c->product->name }}</td> <td>${{ $c->product->price }}</td> <td> <form action="{{ route('cart.update', $c) }}" method="POST" class="d-flex gap-2"> @csrf @method('PUT') <input type="number" name="quantity" value="{{ $c->quantity }}" min="1" max="{{ $c->product->stock }}" class="form-control" style="width: 80px"> <button class="btn btn-sm btn-secondary">Update</button> </form> </td> <td>${{ $c->product->price * $c->quantity }}</td> <td> <form action="{{ route('cart.remove', $c) }}" method="POST"> @csrf @method('DELETE') <button class="btn btn-sm btn-danger">Remove</button> </form> </td> </tr> @endforeach </tbody> </table> <h4>Total: ${{ $total }}</h4> <hr> <h4>Checkout</h4> <form action="{{ route('order.place') }}" method="POST"> @csrf <div class="mb-3"> <label>Delivery Address</label> <textarea name="address" class="form-control" required></textarea> </div> <button class="btn btn-success">Place Order</button> </form> @endif @endsection